mapper.select:
SELECT b.ID, WORKWARE_TYPE_CODE, WORKWARE_TYPE_NAME, b.CREATE_BY, b.CREATE_TIME, s.user_name as create_name FROM m_workware_type b inner join sys_user s on b.create_by = s.id
b.id=#{id}
order by CREATE_TIME desc

SELECT b.ID, TYPE_CODE, MODEL_CODE, MODEL_NAME, b.CREATE_BY, b.CREATE_TIME, s.user_name as create_name FROM m_workware_type_model b inner join sys_user s on b.create_by = s.id
and TYPE_CODE=#{typeCode}
order by CREATE_TIME desc

mapper.update:
UPDATE
    m_workware_type
SET
    workware_type_code=#{workwareTypeCode},
    workware_type_name=#{workwareTypeName}

    id=#{id}
